 12→func TestComputeHash(t *testing.T) {
 13→	t.Parallel()
 14→	h1 := computeHash("name=MIT&sort=distance")
 15→	h2 := computeHash("name=MIT&sort=distance")
 16→	h3 := computeHash("name=Harvard")
 17→
 18→	if h1 != h2 {
 19→		t.Errorf("same input produced different hashes: %q vs %q", h1, h2)
 20→	}
