package savedsearch

import (
	"context"
	"crypto/sha256"
	"encoding/hex"
	"encoding/json"
	"fmt"
	"time"

	"github.com/jackc/pgx/v5/pgxpool"
)

// SavedSearch represents a persisted search configuration.
type SavedSearch struct {
	ID          string
	Name        string
	Hash        string
	SearchState string
	Created     time.Time
	Updated     time.Time
}

// queryJSON is the JSONB wrapper stored in the query column.
type queryJSON struct {
	S string `json:"s"`
}

// Service manages saved searches in the ugc schema.
type Service struct {
	pool *pgxpool.Pool
}

// NewService returns a new saved-search service.
func NewService(pool *pgxpool.Pool) *Service {
	return &Service{pool: pool}
}

// TeamIDForUser looks up the team_id for a given user_id.
func (s *Service) TeamIDForUser(ctx context.Context, userID string) (string, error) {
	var teamID string
	err := s.pool.QueryRow(ctx,
		`SELECT team_id FROM subscription.team_member WHERE user_id = $1`, userID,
	).Scan(&teamID)
	if err != nil {
		return "", fmt.Errorf("savedsearch: team for user %s: %w", userID, err)
	}
	return teamID, nil
}

// List returns all saved searches for the given team, most recently updated first.
func (s *Service) List(ctx context.Context, teamID string) ([]SavedSearch, error) {
	rows, err := s.pool.Query(ctx, `
		SELECT id, name, hash, query, created, updated
		FROM ugc.saved_search
		WHERE team_id = $1
		ORDER BY updated DESC`, teamID)
	if err != nil {
		return nil, fmt.Errorf("savedsearch: list for team %s: %w", teamID, err)
	}
	defer rows.Close()

	var results []SavedSearch
	for rows.Next() {
		var ss SavedSearch
		var raw []byte
		if err := rows.Scan(&ss.ID, &ss.Name, &ss.Hash, &raw, &ss.Created, &ss.Updated); err != nil {
			return nil, fmt.Errorf("savedsearch: scan: %w", err)
		}
		var q queryJSON
		if err := json.Unmarshal(raw, &q); err != nil {
			return nil, fmt.Errorf("savedsearch: unmarshal query for %s: %w", ss.ID, err)
		}
		ss.SearchState = q.S
		results = append(results, ss)
	}
	if err := rows.Err(); err != nil {
		return nil, fmt.Errorf("savedsearch: rows: %w", err)
	}
	return results, nil
}

// Save creates a new saved search and returns it.
func (s *Service) Save(ctx context.Context, teamID, name, searchState string) (*SavedSearch, error) {
	hash := computeHash(searchState)
	q := queryJSON{S: searchState}
	data, err := json.Marshal(q)
	if err != nil {
		return nil, fmt.Errorf("savedsearch: marshal: %w", err)
	}

	var ss SavedSearch
	err = s.pool.QueryRow(ctx, `
		INSERT INTO ugc.saved_search (id, team_id, name, hash, query)
		VALUES (gen_random_uuid()::varchar(62), $1, $2, $3, $4)
		RETURNING id, name, hash, created, updated`,
		teamID, name, hash, data,
	).Scan(&ss.ID, &ss.Name, &ss.Hash, &ss.Created, &ss.Updated)
	if err != nil {
		return nil, fmt.Errorf("savedsearch: save for team %s: %w", teamID, err)
	}
	ss.SearchState = searchState
	return &ss, nil
}

// Delete removes a saved search by ID, scoped to the given team for authorization.
// Returns an error if the row does not exist or belongs to a different team.
func (s *Service) Delete(ctx context.Context, teamID, id string) error {
	tag, err := s.pool.Exec(ctx, `
		DELETE FROM ugc.saved_search
		WHERE id = $1 AND team_id = $2`, id, teamID)
	if err != nil {
		return fmt.Errorf("savedsearch: delete %s: %w", id, err)
	}
	if tag.RowsAffected() == 0 {
		return fmt.Errorf("savedsearch: delete %s: not found or not owned", id)
	}
	return nil
}

// computeHash returns the SHA-256 hex digest of a search state string.
func computeHash(searchState string) string {
	h := sha256.Sum256([]byte(searchState))
	return hex.EncodeToString(h[:])
}

import { Card } from '@mantine/core'
import { MapPin, DollarSign } from 'lucide-react'
import type { SearchInstitution } from './types'

function formatDistance(d: number): string {
  if (d < 1) return '< 1 mi'
  return `${Math.round(d)} mi`
}

function formatPrice(p: number): string {
  return `$${p.toLocaleString()}`
}

export interface InstitutionCardProps {
  institution: SearchInstitution
  hasLocation: boolean
  hasState: boolean
  onClick: () => void
}

export function InstitutionCard({
  institution,
  hasLocation,
  hasState,
  onClick,
}: InstitutionCardProps) {
  return (
    <Card
      shadow="sm"
      padding="md"
      radius="md"
      withBorder
      style={{ cursor: 'pointer' }}
      role="button"
      tabIndex={0}
      onClick={onClick}
      onKeyDown={(e) => {
        if (e.key === 'Enter' || e.key === ' ') {
          e.preventDefault()
          onClick()
        }
      }}
    >
      <p
        style={{
          fontWeight: 600,
          fontSize: '1rem',
          color: 'var(--color-primary)',
          margin: 0,
          marginBottom: 4,
        }}
      >
        {institution.name}
      </p>
      <p
        style={{
          fontSize: '0.875rem',
          color: 'var(--mantine-color-gray-6)',
          margin: 0,
        }}
      >
        {institution.city}, {institution.state}
      </p>
      {(hasLocation || hasState) && (
        <div
          style={{
            display: 'flex',
            gap: 16,
            marginTop: 8,
            fontSize: '0.875rem',
            color: 'var(--mantine-color-gray-6)',
          }}
        >
          {hasLocation && institution.distance != null && (
            <span
              data-testid="distance"
              style={{ display: 'inline-flex', alignItems: 'center', gap: 4 }}
            >
              <MapPin size={14} />
              {formatDistance(institution.distance)}
            </span>
          )}
          {hasState && institution.myPrice != null && (
            <span
              data-testid="my-price"
              style={{ display: 'inline-flex', alignItems: 'center', gap: 4 }}
            >
              <DollarSign size={14} />
              {formatPrice(institution.myPrice)}
            </span>
          )}
        </div>
      )}
    </Card>
  )
}

export function InstitutionCardSkeleton() {
  return (
    <Card
      shadow="sm"
      padding="md"
      radius="md"
      withBorder
      data-testid="result-skeleton"
    >
      <div
        style={{
          height: 16,
          width: '60%',
          backgroundColor: 'var(--mantine-color-gray-2)',
          borderRadius: 4,
          marginBottom: 8,
          animation: 'pulse 1.5s ease-in-out infinite',
        }}
      />
      <div
        style={{
          height: 14,
          width: '35%',
          backgroundColor: 'var(--mantine-color-gray-2)',
          borderRadius: 4,
          animation: 'pulse 1.5s ease-in-out infinite',
        }}
      />
    </Card>
  )
}

import { useState } from 'react'
import {
  Anchor,
  Badge,
  Divider,
  Group,
  Modal,
  SimpleGrid,
  Stack,
  Text,
} from '@mantine/core'
import { Button } from '@/components/ui/button'
import { useMediaQuery } from '@mantine/hooks'
import type { SearchInstitution } from './types'
import { SimilarInstitutions } from './SimilarInstitutions'
import { ENUM_LABELS } from '@/lib/enumLabels'

// ── Formatters ──────────────────────────────────────────────────────────────

function formatPercent(value: number | null | undefined): string {
  if (value == null) return '—'
  return `${(value * 100).toFixed(1)}%`
}

function formatCurrency(value: number | null | undefined): string {
  if (value == null) return '—'
  return `$${value.toLocaleString()}`
}

function formatNumber(value: number | null | undefined): string {
  if (value == null) return '—'
  return value.toLocaleString()
}

function mapLabel(
  value: string | null | undefined,
  labels: Record<string, string>,
): string {
  if (value == null) return '—'
  return labels[value] ?? value
}

function formatRange(low: number | null | undefined, high: number | null | undefined): string {
  if (low == null && high == null) return '—'
  if (low != null && high != null) return `${low.toLocaleString()}–${high.toLocaleString()}`
  if (low != null) return `${low.toLocaleString()}+`
  return `≤${high!.toLocaleString()}`
}

// ── Sub-components ──────────────────────────────────────────────────────────

function DetailRow({ label, value }: { label: string; value: string }) {
  if (value === '—') return null
  return (
    <Group
      justify="space-between"
      style={{ borderBottom: '1px solid var(--mantine-color-gray-2)' }}
      py="xs"
    >
      <Text size="sm" c="dimmed">
        {label}
      </Text>
      <Text size="sm" fw={500}>
        {value}
      </Text>
    </Group>
  )
}

function LinkRow({ label, url }: { label: string; url: string | null | undefined }) {
  if (!url) return null
  const href = url.startsWith('http') ? url : `https://${url}`
  return (
    <Group
      justify="space-between"
      style={{ borderBottom: '1px solid var(--mantine-color-gray-2)' }}
      py="xs"
    >
      <Text size="sm" c="dimmed">
        {label}
      </Text>
      <Anchor href={href} target="_blank" rel="noopener noreferrer" size="sm" fw={500}>
        {url}
      </Anchor>
    </Group>
  )
}

function SectionHeader({ children }: { children: string }) {
  return (
    <Text size="xs" fw={700} tt="uppercase" c="dimmed" mb="xs">
      {children}
    </Text>
  )
}

// ── Props ───────────────────────────────────────────────────────────────────

interface InstitutionDetailProps {
  institution: SearchInstitution | null
  opened: boolean
  onClose: () => void
}

// ── Component ───────────────────────────────────────────────────────────────

export function InstitutionDetail({ institution: inst, opened, onClose }: InstitutionDetailProps) {
  const isMobile = useMediaQuery('(max-width: 48em)')
  const [showSimilar, setShowSimilar] = useState(false)

  return (
    <Modal
      opened={opened}
      onClose={onClose}
      fullScreen={isMobile ?? false}
      size="xl"
      title={inst?.name ?? 'Institution Details'}
      aria-label="Institution details"
    >
      {!inst && (
        <Text c="dimmed" size="sm">
          Institution not found.
        </Text>
      )}
      {inst && (
        <Stack gap="md">
          {/* Header */}
          <Text size="sm" c="dimmed">
            {inst.city}, {inst.state}
          </Text>

          <SimpleGrid cols={{ base: 1, sm: 2 }} spacing="lg">
            {/* Core / Academics */}
            <Stack gap={0}>
              <SectionHeader>Core</SectionHeader>
              <DetailRow
                label="Type"
                value={mapLabel(inst.academics?.institutionType, ENUM_LABELS.institution_type)}
              />
              <DetailRow
                label="Highest Degree"
                value={mapLabel(inst.academics?.highestDegree, ENUM_LABELS.highest_degree)}
              />
              <DetailRow
                label="Student-Faculty Ratio"
                value={
                  inst.academics?.studentFacultyRatio != null
                    ? `${inst.academics.studentFacultyRatio}:1`
                    : '—'
                }
              />
              <DetailRow
                label="Full-Time Faculty"
                value={formatPercent(inst.academics?.fullTimeFacultyRate)}
              />
              <DetailRow
                label="Gender"
                value={
                  inst.academics?.gender === 'coed'
                    ? 'Coeducational'
                    : inst.academics?.gender === 'men-only'
                      ? 'Men Only'
                      : inst.academics?.gender === 'women-only'
                        ? 'Women Only'
                        : '—'
                }
              />
            </Stack>

            {/* Location */}
            <Stack gap={0}>
              <SectionHeader>Location</SectionHeader>
              <DetailRow label="City" value={inst.city} />
              <DetailRow label="State" value={inst.state} />
              <DetailRow
                label="Setting"
                value={mapLabel(inst.locationDetails?.locale, ENUM_LABELS.locale)}
              />
              <DetailRow
                label="Region"
                value={mapLabel(inst.locationDetails?.region, ENUM_LABELS.region)}
              />
              {inst.locationDetails?.metroArea && (
                <DetailRow label="Metro Area" value={inst.locationDetails.metroArea} />
              )}
            </Stack>

            {/* Cost */}
            <Stack gap={0}>
              <SectionHeader>Cost</SectionHeader>
              <DetailRow
                label="In-State Tuition"
                value={formatCurrency(inst.cost?.tuitionInState)}
              />
              <DetailRow
                label="Out-of-State Tuition"
                value={formatCurrency(inst.cost?.tuitionOutOfState)}
              />
              <DetailRow label="Net Price" value={formatCurrency(inst.cost?.avgNetPrice)} />
              <DetailRow label="Room & Board" value={formatCurrency(inst.cost?.roomAndBoard)} />
            </Stack>

            {/* Admissions */}
            <Stack gap={0}>
              <SectionHeader>Admissions</SectionHeader>
              <DetailRow
                label="Acceptance Rate"
                value={formatPercent(inst.outcomes?.admissionRate)}
              />
              <DetailRow
                label="SAT Math"
                value={formatRange(inst.admissions?.satMath25, inst.admissions?.satMath75)}
              />
              <DetailRow
                label="SAT Verbal"
                value={formatRange(inst.admissions?.satVerbal25, inst.admissions?.satVerbal75)}
              />
              <DetailRow
                label="ACT Composite"
                value={formatRange(
                  inst.admissions?.actComposite25,
                  inst.admissions?.actComposite75,
                )}
              />
              {inst.admissions?.applicationPlatforms &&
                inst.admissions.applicationPlatforms.length > 0 && (
                  <DetailRow
                    label="Apply Via"
                    value={inst.admissions.applicationPlatforms.join(', ')}
                  />
                )}
            </Stack>

            {/* Outcomes */}
            <Stack gap={0}>
              <SectionHeader>Outcomes</SectionHeader>
              <DetailRow
                label="Graduation Rate"
                value={formatPercent(inst.outcomes?.graduationRate)}
              />
              <DetailRow
                label="Retention Rate"
                value={formatPercent(inst.outcomes?.retentionRate)}
              />
              <DetailRow
                label="Transfer Rate"
                value={formatPercent(inst.outcomes?.transferRate)}
              />
            </Stack>

            {/* Rankings */}
            {inst.rankings && (
              <Stack gap={0}>
                <SectionHeader>Rankings</SectionHeader>
                <DetailRow
                  label="US News National"
                  value={formatNumber(inst.rankings.usNewsNational)}
                />
                <DetailRow
                  label="US News Liberal Arts"
                  value={formatNumber(inst.rankings.usNewsLiberalArts)}
                />
                <DetailRow label="Forbes" value={formatNumber(inst.rankings.forbes)} />
                <DetailRow
                  label="Wash. Monthly National"
                  value={formatNumber(inst.rankings.washingtonMonthlyNational)}
                />
                <DetailRow
                  label="Wash. Monthly Liberal Arts"
                  value={formatNumber(inst.rankings.washingtonMonthlyLiberalArts)}
                />
                <DetailRow label="Niche" value={formatNumber(inst.rankings.niche)} />
                <DetailRow
                  label="Money Score"
                  value={
                    inst.rankings.moneyScore != null
                      ? inst.rankings.moneyScore.toFixed(1)
                      : '—'
                  }
                />
                {inst.blendScore != null && (
                  <DetailRow label="Blend Score" value={inst.blendScore.toFixed(1)} />
                )}
              </Stack>
            )}

            {/* Athletics */}
            {inst.athletics && (
              <Stack gap={0}>
                <SectionHeader>Athletics</SectionHeader>
                <DetailRow
                  label="NCAA Division"
                  value={mapLabel(inst.athletics.ncaaDivision, ENUM_LABELS.ncaa_division)}
                />
                {inst.athletics.ncaaConference && (
                  <DetailRow label="Conference" value={inst.athletics.ncaaConference} />
                )}
              </Stack>
            )}

            {/* Demographics */}
            {inst.demographics && (
              <Stack gap={0}>
                <SectionHeader>Demographics</SectionHeader>
                <DetailRow
                  label="Total Enrollment"
                  value={formatNumber(inst.demographics.totalEnrollment)}
                />
                {inst.academics?.gradEnrollment != null && (
                  <DetailRow
                    label="Graduate Enrollment"
                    value={formatNumber(inst.academics.gradEnrollment)}
                  />
                )}
                <DetailRow label="Male" value={formatPercent(inst.demographics.percentMale)} />
                <DetailRow
                  label="Female"
                  value={formatPercent(inst.demographics.percentFemale)}
                />
                {(inst.demographics.hbcu ||
                  inst.demographics.hsi ||
                  inst.demographics.aanapisi ||
                  inst.demographics.pbi) && (
                  <Group gap="xs" mt="xs">
                    {inst.demographics.hbcu && (
                      <Badge size="sm" variant="light" color="brand">
                        HBCU
                      </Badge>
                    )}
                    {inst.demographics.hsi && (
                      <Badge size="sm" variant="light" color="brand">
                        HSI
                      </Badge>
                    )}
                    {inst.demographics.aanapisi && (
                      <Badge size="sm" variant="light" color="brand">
                        AANAPISI
                      </Badge>
                    )}
                    {inst.demographics.pbi && (
                      <Badge size="sm" variant="light" color="brand">
                        PBI
                      </Badge>
                    )}
                  </Group>
                )}
              </Stack>
            )}

            {/* Cultural Environment */}
            {inst.culture && (
              <Stack gap={0}>
                <SectionHeader>Cultural Environment</SectionHeader>
                <DetailRow
                  label="Partisan Lean"
                  value={
                    inst.culture.partisanDirection && inst.culture.partisanScore != null
                      ? `${mapLabel(inst.culture.partisanDirection, ENUM_LABELS.partisan_direction)} +${inst.culture.partisanScore.toFixed(1)}`
                      : '—'
                  }
                />
                {inst.culture.religiousAffiliation && (
                  <DetailRow
                    label="Religious Affiliation"
                    value={inst.culture.religiousAffiliation}
                  />
                )}
              </Stack>
            )}

            {/* Weather */}
            {inst.climate && (
              <Stack gap={0}>
                <SectionHeader>Weather</SectionHeader>
                <DetailRow
                  label="Climate"
                  value={mapLabel(inst.climate.koppenClimate, ENUM_LABELS.koppen_climate)}
                />
                <DetailRow
                  label="Temperature"
                  value={inst.climate.koppenTemperature ?? '—'}
                />
                <DetailRow
                  label="Precipitation"
                  value={inst.climate.koppenPrecipitation ?? '—'}
                />
              </Stack>
            )}

            {/* Metadata */}
            {inst.meta && (
              <Stack gap={0}>
                <SectionHeader>Metadata</SectionHeader>
                <LinkRow label="Website" url={inst.meta.schoolUrl} />
                {inst.meta.accreditor && (
                  <DetailRow label="Accreditor" value={inst.meta.accreditor} />
                )}
              </Stack>
            )}
          </SimpleGrid>

          <Divider />

          {!showSimilar ? (
            <Button variant="light" size="sm" onClick={() => setShowSimilar(true)}>
              Find Similar Schools
            </Button>
          ) : (
            <Stack gap="sm">
              <Text size="xs" fw={700} tt="uppercase" c="dimmed">
                Similar Schools
              </Text>
              <SimilarInstitutions unitID={inst.unitID} />
            </Stack>
          )}
        </Stack>
      )}
    </Modal>
  )
}

