package savedsearch

import (
	"context"
	"testing"

	"github.com/jackc/pgx/v5/pgxpool"
	"github.com/ketang/kapow/api/internal/testdb"
	"github.com/ketang/kapow/api/internal/user"
)

func TestComputeHash(t *testing.T) {
	t.Parallel()
	h1 := computeHash("name=MIT&sort=distance")
	h2 := computeHash("name=MIT&sort=distance")
	h3 := computeHash("name=Harvard")

	if h1 != h2 {
		t.Errorf("same input produced different hashes: %q vs %q", h1, h2)
	}
	if h1 == h3 {
		t.Error("different inputs produced same hash")
	}
	if len(h1) != 64 {
		t.Errorf("hash length = %d, want 64", len(h1))
	}
}

func TestNewService(t *testing.T) {
	t.Parallel()
	svc := NewService(nil)
	if svc == nil {
		t.Fatal("NewService returned nil")
	}
}

// ensureTestUser creates a user+team via user.Service and returns the team ID.
func ensureTestUser(t *testing.T, ctx context.Context, pool *pgxpool.Pool, userSvc *user.Service, userID, email string) string {
	t.Helper()
	if err := userSvc.EnsureUser(ctx, userID, email); err != nil {
		t.Fatalf("EnsureUser failed: %v", err)
	}
	var teamID string
	if err := pool.QueryRow(ctx,
		`SELECT team_id FROM subscription.team_member WHERE user_id = $1`, userID,
	).Scan(&teamID); err != nil {
		t.Fatalf("team lookup failed: %v", err)
	}
	return teamID
}

func TestIntegrationList_Empty(t *testing.T) {
	pool := testdb.New(t)
	ctx := context.Background()
	userSvc := user.NewService(pool)
	svc := NewService(pool)

	teamID := ensureTestUser(t, ctx, pool, userSvc, "ss-user-001", "ss1@example.com")

	results, err := svc.List(ctx, teamID)
	if err != nil {
		t.Fatalf("List failed: %v", err)
	}
	if len(results) != 0 {
		t.Errorf("expected 0 results, got %d", len(results))
	}
}

func TestIntegrationSave(t *testing.T) {
	pool := testdb.New(t)
	ctx := context.Background()
	userSvc := user.NewService(pool)
	svc := NewService(pool)

	teamID := ensureTestUser(t, ctx, pool, userSvc, "ss-user-002", "ss2@example.com")

	ss, err := svc.Save(ctx, teamID, "My Search", "name=MIT&sort=distance")
	if err != nil {
		t.Fatalf("Save failed: %v", err)
	}
	if ss.ID == "" {
		t.Error("expected non-empty ID")
	}
	if ss.Name != "My Search" {
		t.Errorf("Name = %q, want %q", ss.Name, "My Search")
	}
	if ss.SearchState != "name=MIT&sort=distance" {
		t.Errorf("SearchState = %q, want %q", ss.SearchState, "name=MIT&sort=distance")
	}
	if ss.Created.IsZero() {
		t.Error("expected non-zero Created")
	}
}

func TestIntegrationSaveAndList(t *testing.T) {
	pool := testdb.New(t)
	ctx := context.Background()
	userSvc := user.NewService(pool)
	svc := NewService(pool)

	teamID := ensureTestUser(t, ctx, pool, userSvc, "ss-user-003", "ss3@example.com")

	_, err := svc.Save(ctx, teamID, "Search A", "name=MIT")
	if err != nil {
		t.Fatalf("Save A failed: %v", err)
	}
	_, err = svc.Save(ctx, teamID, "Search B", "name=Harvard")
	if err != nil {
		t.Fatalf("Save B failed: %v", err)
	}

	results, err := svc.List(ctx, teamID)
	if err != nil {
		t.Fatalf("List failed: %v", err)
	}
	if len(results) != 2 {
		t.Fatalf("expected 2 results, got %d", len(results))
	}
	// Most recent first
	if results[0].Name != "Search B" {
		t.Errorf("first result = %q, want Search B", results[0].Name)
	}
}

func TestIntegrationDelete(t *testing.T) {
	pool := testdb.New(t)
	ctx := context.Background()
	userSvc := user.NewService(pool)
	svc := NewService(pool)

	teamID := ensureTestUser(t, ctx, pool, userSvc, "ss-user-004", "ss4@example.com")

	ss, err := svc.Save(ctx, teamID, "To Delete", "name=MIT")
	if err != nil {
		t.Fatalf("Save failed: %v", err)
	}

	if err := svc.Delete(ctx, teamID, ss.ID); err != nil {
		t.Fatalf("Delete failed: %v", err)
	}

	results, err := svc.List(ctx, teamID)
	if err != nil {
		t.Fatalf("List failed: %v", err)
	}
	if len(results) != 0 {
		t.Errorf("expected 0 results after delete, got %d", len(results))
	}
}

func TestIntegrationDelete_WrongTeam(t *testing.T) {
	pool := testdb.New(t)
	ctx := context.Background()
	userSvc := user.NewService(pool)
	svc := NewService(pool)

	teamA := ensureTestUser(t, ctx, pool, userSvc, "ss-user-005a", "ss5a@example.com")
	teamB := ensureTestUser(t, ctx, pool, userSvc, "ss-user-005b", "ss5b@example.com")

	ss, err := svc.Save(ctx, teamA, "Team A Search", "name=MIT")
	if err != nil {
		t.Fatalf("Save failed: %v", err)
	}

	// Team B should not be able to delete Team A's search
	err = svc.Delete(ctx, teamB, ss.ID)
	if err == nil {
		t.Fatal("expected error when deleting another team's search")
	}

	// Verify it still exists
	results, err := svc.List(ctx, teamA)
	if err != nil {
		t.Fatalf("List failed: %v", err)
	}
	if len(results) != 1 {
		t.Errorf("expected 1 result, got %d", len(results))
	}
}

func TestIntegrationTeamIDForUser(t *testing.T) {
	pool := testdb.New(t)
	ctx := context.Background()
	userSvc := user.NewService(pool)
	svc := NewService(pool)

	expected := ensureTestUser(t, ctx, pool, userSvc, "ss-user-006", "ss6@example.com")

	got, err := svc.TeamIDForUser(ctx, "ss-user-006")
	if err != nil {
		t.Fatalf("TeamIDForUser failed: %v", err)
	}
	if got != expected {
		t.Errorf("TeamIDForUser = %q, want %q", got, expected)
	}
}

