package bookmark

import (
	"context"
	"fmt"
	"time"

	"github.com/jackc/pgx/v5/pgxpool"
)

// SavedInstitution represents a bookmarked institution.
type SavedInstitution struct {
	ID      string
	UnitID  string
	Name    string
	City    string
	State   string
	Created time.Time
}

// Service manages bookmarked institutions in the ugc schema.
type Service struct {
	pool *pgxpool.Pool
}

// NewService returns a new bookmark service.
func NewService(pool *pgxpool.Pool) *Service {
	return &Service{pool: pool}
}

// TeamIDForUser looks up the team_id for a given user_id.
func (s *Service) TeamIDForUser(ctx context.Context, userID string) (string, error) {
	var teamID string
	err := s.pool.QueryRow(ctx,
		`SELECT team_id FROM subscription.team_member WHERE user_id = $1`, userID,
	).Scan(&teamID)
	if err != nil {
		return "", fmt.Errorf("bookmark: team for user %s: %w", userID, err)
	}
	return teamID, nil
}

// List returns all bookmarked institutions for the given team, most recent first.
func (s *Service) List(ctx context.Context, teamID string) ([]SavedInstitution, error) {
	rows, err := s.pool.Query(ctx, `
		SELECT si.id, si.unit_id, i.institution_name, i.city, i.state, si.created
		FROM ugc.saved_institution si
		JOIN search_base.institution i ON si.unit_id = i.unit_id
		WHERE si.team_id = $1
		ORDER BY si.created DESC`, teamID)
	if err != nil {
		return nil, fmt.Errorf("bookmark: list for team %s: %w", teamID, err)
	}
	defer rows.Close()

	var results []SavedInstitution
	for rows.Next() {
		var si SavedInstitution
		if err := rows.Scan(&si.ID, &si.UnitID, &si.Name, &si.City, &si.State, &si.Created); err != nil {
			return nil, fmt.Errorf("bookmark: scan: %w", err)
		}
		results = append(results, si)
	}
	if err := rows.Err(); err != nil {
		return nil, fmt.Errorf("bookmark: rows: %w", err)
	}
	return results, nil
}

// Add bookmarks an institution for the given team. Idempotent via upsert.
func (s *Service) Add(ctx context.Context, teamID, unitID string) (*SavedInstitution, error) {
	var si SavedInstitution
	err := s.pool.QueryRow(ctx, `
		INSERT INTO ugc.saved_institution (id, team_id, unit_id, bookmarked, note)
		VALUES (gen_random_uuid()::varchar(62), $1, $2, true, '')
		ON CONFLICT (unit_id, team_id)
		DO UPDATE SET bookmarked = true, updated = CURRENT_TIMESTAMP
		RETURNING id, unit_id, created`,
		teamID, unitID,
	).Scan(&si.ID, &si.UnitID, &si.Created)
	if err != nil {
		return nil, fmt.Errorf("bookmark: add %s for team %s: %w", unitID, teamID, err)
	}

	// Fetch institution details for the response.
	err = s.pool.QueryRow(ctx, `
		SELECT institution_name, city, state
		FROM search_base.institution WHERE unit_id = $1`, unitID,
	).Scan(&si.Name, &si.City, &si.State)
	if err != nil {
		return nil, fmt.Errorf("bookmark: institution lookup %s: %w", unitID, err)
	}

	return &si, nil
}

// Remove deletes a bookmark for the given team and unit_id.
func (s *Service) Remove(ctx context.Context, teamID, unitID string) error {
	tag, err := s.pool.Exec(ctx, `
		DELETE FROM ugc.saved_institution
		WHERE team_id = $1 AND unit_id = $2`, teamID, unitID)
	if err != nil {
		return fmt.Errorf("bookmark: remove %s: %w", unitID, err)
	}
	if tag.RowsAffected() == 0 {
		return fmt.Errorf("bookmark: remove %s: not found or not owned", unitID)
	}
	return nil
}

// IsBookmarkedBatch checks which of the given unit_ids are bookmarked by the team.
func (s *Service) IsBookmarkedBatch(ctx context.Context, teamID string, unitIDs []string) (map[string]bool, error) {
	result := make(map[string]bool, len(unitIDs))

	if len(unitIDs) == 0 {
		return result, nil
	}

	rows, err := s.pool.Query(ctx, `
		SELECT unit_id FROM ugc.saved_institution
		WHERE team_id = $1 AND unit_id = ANY($2)`, teamID, unitIDs)
	if err != nil {
		return nil, fmt.Errorf("bookmark: batch check: %w", err)
	}
	defer rows.Close()

	for rows.Next() {
		var uid string
		if err := rows.Scan(&uid); err != nil {
			return nil, fmt.Errorf("bookmark: batch scan: %w", err)
		}
		result[uid] = true
	}
	if err := rows.Err(); err != nil {
		return nil, fmt.Errorf("bookmark: batch rows: %w", err)
	}
