package bookmark

import (
	"context"
	"testing"

	"github.com/jackc/pgx/v5/pgxpool"
	"github.com/ketang/kapow/api/internal/testdb"
	"github.com/ketang/kapow/api/internal/user"
)

func TestNewService(t *testing.T) {
	t.Parallel()
	svc := NewService(nil)
	if svc == nil {
		t.Fatal("NewService returned nil")
	}
}

// ensureTestUser creates a user+team via user.Service and returns the team ID.
func ensureTestUser(t *testing.T, ctx context.Context, pool *pgxpool.Pool, userSvc *user.Service, userID, email string) string {
	t.Helper()
	if err := userSvc.EnsureUser(ctx, userID, email); err != nil {
		t.Fatalf("EnsureUser failed: %v", err)
	}
	var teamID string
	if err := pool.QueryRow(ctx,
		`SELECT team_id FROM subscription.team_member WHERE user_id = $1`, userID,
	).Scan(&teamID); err != nil {
		t.Fatalf("team lookup failed: %v", err)
	}
	return teamID
}

// fixtureUnitID is a unit_id present in the sample fixture data.
const fixtureUnitID = "100724"     // Alabama State University
const fixtureUnitID2 = "101240"    // Gadsden State Community College

func TestIntegrationList_Empty(t *testing.T) {
	pool := testdb.New(t)
	ctx := context.Background()
	userSvc := user.NewService(pool)
	svc := NewService(pool)

	teamID := ensureTestUser(t, ctx, pool, userSvc, "bk-user-001", "bk1@example.com")

	results, err := svc.List(ctx, teamID)
	if err != nil {
		t.Fatalf("List failed: %v", err)
	}
	if len(results) != 0 {
		t.Errorf("expected 0 results, got %d", len(results))
	}
}

func TestIntegrationAdd(t *testing.T) {
	pool := testdb.New(t)
	ctx := context.Background()
	userSvc := user.NewService(pool)
	svc := NewService(pool)

	teamID := ensureTestUser(t, ctx, pool, userSvc, "bk-user-002", "bk2@example.com")

	si, err := svc.Add(ctx, teamID, fixtureUnitID)
	if err != nil {
		t.Fatalf("Add failed: %v", err)
	}
	if si.ID == "" {
		t.Error("expected non-empty ID")
	}
	if si.UnitID != fixtureUnitID {
		t.Errorf("UnitID = %q, want %q", si.UnitID, fixtureUnitID)
	}
	if si.Name == "" {
		t.Error("expected non-empty Name")
	}
	if si.Created.IsZero() {
		t.Error("expected non-zero Created")
	}
}

func TestIntegrationAdd_Idempotent(t *testing.T) {
	pool := testdb.New(t)
	ctx := context.Background()
	userSvc := user.NewService(pool)
	svc := NewService(pool)

	teamID := ensureTestUser(t, ctx, pool, userSvc, "bk-user-003", "bk3@example.com")

	si1, err := svc.Add(ctx, teamID, fixtureUnitID)
	if err != nil {
		t.Fatalf("first Add failed: %v", err)
	}

	si2, err := svc.Add(ctx, teamID, fixtureUnitID)
	if err != nil {
		t.Fatalf("second Add failed: %v", err)
	}

	// Same row should be returned (same ID).
	if si1.ID != si2.ID {
		t.Errorf("idempotent Add returned different IDs: %q vs %q", si1.ID, si2.ID)
	}
}

func TestIntegrationAddAndList(t *testing.T) {
	pool := testdb.New(t)
	ctx := context.Background()
	userSvc := user.NewService(pool)
	svc := NewService(pool)

	teamID := ensureTestUser(t, ctx, pool, userSvc, "bk-user-004", "bk4@example.com")

	if _, err := svc.Add(ctx, teamID, fixtureUnitID); err != nil {
		t.Fatalf("Add 1 failed: %v", err)
	}
	if _, err := svc.Add(ctx, teamID, fixtureUnitID2); err != nil {
		t.Fatalf("Add 2 failed: %v", err)
	}

	results, err := svc.List(ctx, teamID)
	if err != nil {
		t.Fatalf("List failed: %v", err)
	}
	if len(results) != 2 {
		t.Fatalf("expected 2 results, got %d", len(results))
	}
	// Most recent first
	if results[0].UnitID != fixtureUnitID2 {
		t.Errorf("first result UnitID = %q, want %q", results[0].UnitID, fixtureUnitID2)
	}
}

func TestIntegrationRemove(t *testing.T) {
	pool := testdb.New(t)
	ctx := context.Background()
	userSvc := user.NewService(pool)
	svc := NewService(pool)

	teamID := ensureTestUser(t, ctx, pool, userSvc, "bk-user-005", "bk5@example.com")

	if _, err := svc.Add(ctx, teamID, fixtureUnitID); err != nil {
		t.Fatalf("Add failed: %v", err)
	}

	if err := svc.Remove(ctx, teamID, fixtureUnitID); err != nil {
		t.Fatalf("Remove failed: %v", err)
	}

	results, err := svc.List(ctx, teamID)
	if err != nil {
		t.Fatalf("List failed: %v", err)
	}
	if len(results) != 0 {
		t.Errorf("expected 0 results after remove, got %d", len(results))
	}
}

func TestIntegrationRemove_WrongTeam(t *testing.T) {
	pool := testdb.New(t)
	ctx := context.Background()
	userSvc := user.NewService(pool)
	svc := NewService(pool)

	teamA := ensureTestUser(t, ctx, pool, userSvc, "bk-user-006a", "bk6a@example.com")
	teamB := ensureTestUser(t, ctx, pool, userSvc, "bk-user-006b", "bk6b@example.com")

	if _, err := svc.Add(ctx, teamA, fixtureUnitID); err != nil {
		t.Fatalf("Add failed: %v", err)
	}

	// Team B should not be able to remove Team A's bookmark
	err := svc.Remove(ctx, teamB, fixtureUnitID)
	if err == nil {
		t.Fatal("expected error when removing another team's bookmark")
	}

	// Verify it still exists
	results, err := svc.List(ctx, teamA)
	if err != nil {
		t.Fatalf("List failed: %v", err)
	}
	if len(results) != 1 {
		t.Errorf("expected 1 result, got %d", len(results))
	}
}

func TestIntegrationIsBookmarkedBatch(t *testing.T) {
	pool := testdb.New(t)
	ctx := context.Background()
	userSvc := user.NewService(pool)
	svc := NewService(pool)

	teamID := ensureTestUser(t, ctx, pool, userSvc, "bk-user-007", "bk7@example.com")

	if _, err := svc.Add(ctx, teamID, fixtureUnitID); err != nil {
		t.Fatalf("Add failed: %v", err)
	}

	result, err := svc.IsBookmarkedBatch(ctx, teamID, []string{fixtureUnitID, fixtureUnitID2})
	if err != nil {
		t.Fatalf("IsBookmarkedBatch failed: %v", err)
	}
	if !result[fixtureUnitID] {
		t.Errorf("expected %q to be bookmarked", fixtureUnitID)
	}
	if result[fixtureUnitID2] {
		t.Errorf("expected %q to NOT be bookmarked", fixtureUnitID2)
	}
}

func TestIntegrationIsBookmarkedBatch_Empty(t *testing.T) {
	pool := testdb.New(t)
	ctx := context.Background()
	userSvc := user.NewService(pool)
	svc := NewService(pool)

	teamID := ensureTestUser(t, ctx, pool, userSvc, "bk-user-008", "bk8@example.com")

	result, err := svc.IsBookmarkedBatch(ctx, teamID, []string{})
	if err != nil {
		t.Fatalf("IsBookmarkedBatch failed: %v", err)
	}
	if len(result) != 0 {
		t.Errorf("expected empty result, got %d", len(result))
	}
}

func TestIntegrationTeamIDForUser(t *testing.T) {
	pool := testdb.New(t)
	ctx := context.Background()
	userSvc := user.NewService(pool)
	svc := NewService(pool)

	expected := ensureTestUser(t, ctx, pool, userSvc, "bk-user-009", "bk9@example.com")

	got, err := svc.TeamIDForUser(ctx, "bk-user-009")
	if err != nil {
		t.Fatalf("TeamIDForUser failed: %v", err)
	}
	if got != expected {
		t.Errorf("TeamIDForUser = %q, want %q", got, expected)
	}
}

