	"github.com/ketang/kapow/api/internal/auth"
)

// AddBookmark is the resolver for the addBookmark field.
func (r *mutationResolver) AddBookmark(ctx context.Context, unitID string) (*model.BookmarkedInstitution, error) {
	claims := auth.GetClaims(ctx)
	if claims == nil || claims.Subject == "" {
		return nil, fmt.Errorf("addBookmark: authentication required")
	}

	teamID, err := r.Bookmark.TeamIDForUser(ctx, claims.Subject)
	if err != nil {
		return nil, fmt.Errorf("addBookmark: %w", err)
	}

	si, err := r.Bookmark.Add(ctx, teamID, unitID)
	if err != nil {
		return nil, fmt.Errorf("addBookmark: %w", err)
	}

	return &model.BookmarkedInstitution{
		ID:        si.ID,
		UnitID:    si.UnitID,
		Name:      si.Name,
		City:      si.City,
		State:     si.State,
		CreatedAt: si.Created.Format("2006-01-02T15:04:05Z"),
	}, nil
}

// RemoveBookmark is the resolver for the removeBookmark field.
func (r *mutationResolver) RemoveBookmark(ctx context.Context, unitID string) (bool, error) {
	claims := auth.GetClaims(ctx)
	if claims == nil || claims.Subject == "" {
		return false, fmt.Errorf("removeBookmark: authentication required")
	}

	teamID, err := r.Bookmark.TeamIDForUser(ctx, claims.Subject)
	if err != nil {
		return false, fmt.Errorf("removeBookmark: %w", err)
	}

	if err := r.Bookmark.Remove(ctx, teamID, unitID); err != nil {
		return false, fmt.Errorf("removeBookmark: %w", err)
	}

	return true, nil
}

// BookmarkedInstitutions is the resolver for the bookmarkedInstitutions field.
func (r *queryResolver) BookmarkedInstitutions(ctx context.Context) ([]*model.BookmarkedInstitution, error) {
	claims := auth.GetClaims(ctx)
	if claims == nil || claims.Subject == "" {
		return []*model.BookmarkedInstitution{}, nil
	}

	teamID, err := r.Bookmark.TeamIDForUser(ctx, claims.Subject)
	if err != nil {
		return nil, fmt.Errorf("bookmarkedInstitutions: %w", err)
	}

	list, err := r.Bookmark.List(ctx, teamID)
	if err != nil {
		return nil, fmt.Errorf("bookmarkedInstitutions: %w", err)
	}

	results := make([]*model.BookmarkedInstitution, len(list))
	for i, si := range list {
		results[i] = &model.BookmarkedInstitution{
			ID:        si.ID,
			UnitID:    si.UnitID,
			Name:      si.Name,
			City:      si.City,
			State:     si.State,
			CreatedAt: si.Created.Format("2006-01-02T15:04:05Z"),
		}
	}
	return results, nil
}

// BookmarkedUnitIDs is the resolver for the bookmarkedUnitIDs field.
func (r *queryResolver) BookmarkedUnitIDs(ctx context.Context, unitIDs []string) ([]string, error) {
	claims := auth.GetClaims(ctx)
	if claims == nil || claims.Subject == "" {
		return []string{}, nil
	}

	teamID, err := r.Bookmark.TeamIDForUser(ctx, claims.Subject)
	if err != nil {
		return nil, fmt.Errorf("bookmarkedUnitIDs: %w", err)
	}

	bookmarked, err := r.Bookmark.IsBookmarkedBatch(ctx, teamID, unitIDs)
	if err != nil {
		return nil, fmt.Errorf("bookmarkedUnitIDs: %w", err)
	}

	var result []string
	for _, uid := range unitIDs {
		if bookmarked[uid] {
			result = append(result, uid)
		}
	}
	if result == nil {
		result = []string{}
	}
	return result, nil
}

