import { create } from 'zustand'
import { graphql } from 'gql.tada'
import { urqlClient } from '@/lib/urqlClient'

const SavedSearchesQuery = graphql(`
  query SavedSearches {
    savedSearches {
      id
      name
      searchState
      createdAt
      updatedAt
    }
  }
`)

const SaveSearchMutation = graphql(`
  mutation SaveSearch($input: SaveSearchInput!) {
    saveSearch(input: $input) {
      id
      name
      searchState
      createdAt
      updatedAt
    }
  }
`)

const DeleteSavedSearchMutation = graphql(`
  mutation DeleteSavedSearch($id: String!) {
    deleteSavedSearch(id: $id)
  }
`)

export interface SavedSearchItem {
  id: string
  name: string
  searchState: string
  createdAt: string
  updatedAt: string
}

interface SavedSearchState {
  searches: SavedSearchItem[]
  loaded: boolean
  loading: boolean

  load: () => Promise<void>
  save: (name: string, searchState: string) => Promise<SavedSearchItem | null>
  remove: (id: string) => Promise<boolean>
  clear: () => void
}

export const useSavedSearchStore = create<SavedSearchState>()((set, get) => ({
  searches: [],
  loaded: false,
  loading: false,

  load: async () => {
    if (get().loaded || get().loading) return
    set({ loading: true })
    try {
      const result = await urqlClient
        .query<{ savedSearches: SavedSearchItem[] }>(SavedSearchesQuery, {})
        .toPromise()
      if (result.data?.savedSearches) {
        set({ searches: result.data.savedSearches, loaded: true })
      }
    } finally {
      set({ loading: false })
    }
  },

  save: async (name, searchState) => {
    const result = await urqlClient
      .mutation<{ saveSearch: SavedSearchItem }>(SaveSearchMutation, {
        input: { name, searchState },
      })
      .toPromise()
    const saved = result.data?.saveSearch ?? null
    if (saved) {
      set((state) => ({ searches: [saved, ...state.searches] }))
    }
    return saved
  },

  remove: async (id) => {
    const result = await urqlClient
      .mutation<{ deleteSavedSearch: boolean }>(DeleteSavedSearchMutation, { id })
      .toPromise()
    if (result.data?.deleteSavedSearch) {
      set((state) => ({ searches: state.searches.filter((s) => s.id !== id) }))
      return true
    }
    return false
  },

  clear: () => {
    set({ searches: [], loaded: false, loading: false })
  },
}))

import { useState, useCallback } from 'react'
import { Popover, TextInput, Group, Text, Tooltip, Stack, ActionIcon } from '@mantine/core'
import { Bookmark } from 'lucide-react'
import { Button } from '@/components/ui/button'
import { useAuthStore } from '@/stores/authStore'
import { useSavedSearchStore } from '@/stores/savedSearchStore'

interface SaveSearchButtonProps {
  searchParams: URLSearchParams
}

export function SaveSearchButton({ searchParams }: SaveSearchButtonProps) {
  const user = useAuthStore((s) => s.user)
  const save = useSavedSearchStore((s) => s.save)
  const [opened, setOpened] = useState(false)
  const [name, setName] = useState('')
  const [saving, setSaving] = useState(false)
  const [feedback, setFeedback] = useState<{ type: 'success' | 'error'; message: string } | null>(
    null,
  )

  const handleSave = useCallback(async () => {
    if (!name.trim()) return
    setSaving(true)
    setFeedback(null)

    // Strip pagination params — not useful when restoring
    const params = new URLSearchParams(searchParams)
    params.delete('page')
    params.delete('pageSize')
    const searchState = params.toString()

    const result = await save(name.trim(), searchState)
    setSaving(false)

    if (result) {
      setFeedback({ type: 'success', message: 'Saved!' })
      setTimeout(() => {
        setOpened(false)
        setName('')
        setFeedback(null)
      }, 1000)
    } else {
      setFeedback({ type: 'error', message: 'Failed to save.' })
    }
  }, [name, searchParams, save])

  if (!user) {
    return (
      <Tooltip label="Sign in to save searches">
        <ActionIcon variant="outline" size="sm" disabled aria-label="Save search">
          <Bookmark size={14} />
        </ActionIcon>
      </Tooltip>
    )
  }

  return (
    <Popover opened={opened} onChange={setOpened} position="bottom-end" shadow="md" width={280}>
      <Popover.Target>
        <Button
          variant="outline"
          size="xs"
          leftSection={<Bookmark size={14} />}
          onClick={() => setOpened((o) => !o)}
        >
          Save
        </Button>
      </Popover.Target>
      <Popover.Dropdown>
        <Stack gap="xs">
          <TextInput
            label="Search name"
            placeholder="e.g. Top engineering schools"
            value={name}
            onChange={(e) => setName(e.currentTarget.value)}
            maxLength={255}
            onKeyDown={(e) => {
              if (e.key === 'Enter') void handleSave()
            }}
            data-autofocus
          />
          {feedback && (
            <Text size="xs" c={feedback.type === 'success' ? 'green' : 'red'}>
              {feedback.message}
            </Text>
          )}
          <Group justify="flex-end">
            <Button variant="outline" size="xs" onClick={() => setOpened(false)}>
              Cancel
            </Button>
            <Button
              size="xs"
              onClick={() => void handleSave()}
              disabled={!name.trim() || saving}
            >
              {saving ? 'Saving...' : 'Save'}
            </Button>
          </Group>
        </Stack>
      </Popover.Dropdown>
    </Popover>
  )
}

import { useEffect } from 'react'
import { useNavigate } from 'react-router-dom'
import { Drawer, Stack, Group, Text, ActionIcon, Loader } from '@mantine/core'
import { Trash2, ExternalLink } from 'lucide-react'
import { useSavedSearchStore } from '@/stores/savedSearchStore'

interface SavedSearchesDrawerProps {
  opened: boolean
  onClose: () => void
}

export function SavedSearchesDrawer({ opened, onClose }: SavedSearchesDrawerProps) {
  const navigate = useNavigate()
  const searches = useSavedSearchStore((s) => s.searches)
  const loaded = useSavedSearchStore((s) => s.loaded)
  const loading = useSavedSearchStore((s) => s.loading)
  const load = useSavedSearchStore((s) => s.load)
  const remove = useSavedSearchStore((s) => s.remove)

  useEffect(() => {
    if (opened) void load()
  }, [opened, load])

  const handleRestore = (searchState: string) => {
    void navigate(`/search?${searchState}`)
    onClose()
  }

  const handleDelete = async (id: string) => {
    await remove(id)
  }

  return (
    <Drawer
      opened={opened}
      onClose={onClose}
      title="Saved Searches"
      position="right"
      size="sm"
    >
      {loading && !loaded ? (
        <Stack align="center" py="xl">
          <Loader size="sm" />
        </Stack>
      ) : searches.length === 0 ? (
        <Text c="dimmed" size="sm" py="xl" ta="center">
          No saved searches yet. Use the Save button on the search page to save your current
          search.
        </Text>
      ) : (
        <Stack gap="xs">
          {searches.map((ss) => (
            <Group
              key={ss.id}
              justify="space-between"
              p="sm"
              style={{
                borderRadius: 'var(--mantine-radius-sm)',
                border: '1px solid var(--mantine-color-gray-3)',
                cursor: 'pointer',
              }}
              onClick={() => handleRestore(ss.searchState)}
            >
              <Stack gap={2} style={{ flex: 1, minWidth: 0 }}>
                <Text size="sm" fw={500} truncate>
                  {ss.name}
                </Text>
                <Text size="xs" c="dimmed">
                  {new Date(ss.updatedAt).toLocaleDateString()}
                </Text>
              </Stack>
              <Group gap="xs">
                <ActionIcon
                  variant="subtle"
                  size="sm"
                  c="dimmed"
                  aria-label="Restore search"
                  onClick={(e) => {
                    e.stopPropagation()
                    handleRestore(ss.searchState)
                  }}
                >
                  <ExternalLink size={14} />
                </ActionIcon>
                <ActionIcon
                  variant="subtle"
                  size="sm"
                  c="red"
                  aria-label="Delete saved search"
                  onClick={(e) => {
                    e.stopPropagation()
                    void handleDelete(ss.id)
                  }}
                >
                  <Trash2 size={14} />
                </ActionIcon>
              </Group>
            </Group>
          ))}
        </Stack>
      )}
    </Drawer>
  )
}

