          {},
        )
        .toPromise()
      if (result.data?.bookmarkedInstitutions) {
        const items = result.data.bookmarkedInstitutions
        const ids = new Set(items.map((i) => i.unitID))
        set({ institutions: items, bookmarkedIDs: ids, loaded: true })
      }
    } finally {
      set({ loading: false })
    }
  },

