    if (unitIDs.length === 0) return
    const result = await urqlClient
      .query<{ bookmarkedUnitIDs: string[] }>(BookmarkedUnitIDsQuery, { unitIDs })
      .toPromise()
    if (result.data?.bookmarkedUnitIDs) {
      set((state) => {
        const newIDs = new Set(state.bookmarkedIDs)
        for (const id of result.data!.bookmarkedUnitIDs) {
          newIDs.add(id)
        }
        return { bookmarkedIDs: newIDs }
      })
    }
