    })

    const result = await urqlClient
      .mutation<{ addBookmark: BookmarkedInstitutionItem }>(AddBookmarkMutation, { unitID })
      .toPromise()

    if (result.data?.addBookmark) {
      const item = result.data.addBookmark
      set((state) => ({
        institutions: [item, ...state.institutions.filter((i) => i.unitID !== unitID)],
      }))
      return true
    }

    // Rollback on failure
    set((state) => {
      const newIDs = new Set(state.bookmarkedIDs)
      newIDs.delete(unitID)
      return { bookmarkedIDs: newIDs }
    })
    return false
  },

  remove: async (unitID: string) => {
    // Optimistic update
    set((state) => {
      const newIDs = new Set(state.bookmarkedIDs)
      newIDs.delete(unitID)
      return { bookmarkedIDs: newIDs }
    })

    const result = await urqlClient
      .mutation<{ removeBookmark: boolean }>(RemoveBookmarkMutation, { unitID })
      .toPromise()

    if (result.data?.removeBookmark) {
      set((state) => ({
        institutions: state.institutions.filter((i) => i.unitID !== unitID),
      }))
      return true
    }

    // Rollback on failure
    set((state) => {
      const newIDs = new Set(state.bookmarkedIDs)
      newIDs.add(unitID)
      return { bookmarkedIDs: newIDs }
    })
    return false
  },

  isBookmarked: (unitID: string) => {
    return get().bookmarkedIDs.has(unitID)
  },

  clear: () => {
    set({ bookmarkedIDs: new Set(), institutions: [], loaded: false, loading: false })
  },
}))

