import { useCallback } from 'react'
import { ActionIcon, Tooltip } from '@mantine/core'
import { Heart } from 'lucide-react'
import { useAuthStore } from '@/stores/authStore'
import { useBookmarkStore } from '@/stores/bookmarkStore'

interface BookmarkButtonProps {
  unitID: string
  size?: 'sm' | 'md'
}

export function BookmarkButton({ unitID, size = 'sm' }: BookmarkButtonProps) {
  const user = useAuthStore((s) => s.user)
  const isBookmarked = useBookmarkStore((s) => s.isBookmarked(unitID))
  const add = useBookmarkStore((s) => s.add)
  const remove = useBookmarkStore((s) => s.remove)

  const handleClick = useCallback(
    (e: React.MouseEvent) => {
      e.stopPropagation()
      e.preventDefault()
      if (isBookmarked) {
        void remove(unitID)
      } else {
        void add(unitID)
      }
    },
    [unitID, isBookmarked, add, remove],
  )

  const handleKeyDown = useCallback(
    (e: React.KeyboardEvent) => {
      if (e.key === 'Enter' || e.key === ' ') {
        e.stopPropagation()
        e.preventDefault()
        if (isBookmarked) {
          void remove(unitID)
        } else {
          void add(unitID)
        }
      }
    },
    [unitID, isBookmarked, add, remove],
  )

  const iconSize = size === 'sm' ? 14 : 18

  if (!user) {
    return (
      <Tooltip label="Sign in to bookmark">
        <ActionIcon
          variant="subtle"
          size={size}
          disabled
          aria-label="Bookmark"
          data-testid="bookmark-button"
        >
          <Heart size={iconSize} />
        </ActionIcon>
      </Tooltip>
    )
  }

  return (
    <Tooltip label={isBookmarked ? 'Remove bookmark' : 'Bookmark'}>
      <ActionIcon
        variant="subtle"
        size={size}
        onClick={handleClick}
        onKeyDown={handleKeyDown}
        aria-label={isBookmarked ? 'Remove bookmark' : 'Bookmark'}
        data-testid="bookmark-button"
        c={isBookmarked ? 'red' : 'dimmed'}
      >
        <Heart size={iconSize} fill={isBookmarked ? 'currentColor' : 'none'} />
      </ActionIcon>
    </Tooltip>
  )
}

