import { useEffect } from 'react'
import { Drawer, Stack, Group, Text, ActionIcon, Loader } from '@mantine/core'
import { Trash2 } from 'lucide-react'
import { useBookmarkStore } from '@/stores/bookmarkStore'

interface BookmarksDrawerProps {
  opened: boolean
  onClose: () => void
}

export function BookmarksDrawer({ opened, onClose }: BookmarksDrawerProps) {
  const institutions = useBookmarkStore((s) => s.institutions)
  const loaded = useBookmarkStore((s) => s.loaded)
  const loading = useBookmarkStore((s) => s.loading)
  const loadAll = useBookmarkStore((s) => s.loadAll)
  const remove = useBookmarkStore((s) => s.remove)

  useEffect(() => {
    if (opened) void loadAll()
  }, [opened, loadAll])

  const handleRemove = async (e: React.MouseEvent, unitID: string) => {
    e.stopPropagation()
    await remove(unitID)
  }

  return (
    <Drawer
      opened={opened}
      onClose={onClose}
      title="Bookmarked Colleges"
      position="right"
      size="sm"
    >
      {loading && !loaded ? (
        <Stack align="center" py="xl">
          <Loader size="sm" />
        </Stack>
      ) : institutions.length === 0 ? (
        <Text c="dimmed" size="sm" py="xl" ta="center">
          No bookmarked colleges yet. Click the heart icon on any college to bookmark it.
        </Text>
      ) : (
        <Stack gap="xs">
          {institutions.map((inst) => (
            <Group
              key={inst.id}
              justify="space-between"
              p="sm"
              style={{
                borderRadius: 'var(--mantine-radius-sm)',
                border: '1px solid var(--mantine-color-gray-3)',
              }}
            >
              <Stack gap={2} style={{ flex: 1, minWidth: 0 }}>
                <Text size="sm" fw={500} truncate>
                  {inst.name}
                </Text>
                <Text size="xs" c="dimmed">
                  {inst.city}, {inst.state}
                </Text>
              </Stack>
              <ActionIcon
                variant="subtle"
                size="sm"
                c="red"
                aria-label={`Remove ${inst.name} bookmark`}
                onClick={(e) => void handleRemove(e, inst.unitID)}
              >
                <Trash2 size={14} />
              </ActionIcon>
            </Group>
          ))}
        </Stack>
      )}
    </Drawer>
  )
}

