  hasLocation,
  hasState,
  onClick,
}: InstitutionCardProps) {
  return (
    <Card
      shadow="sm"
      padding="md"
      radius="md"
      withBorder
      style={{ cursor: 'pointer' }}
      role="button"
      tabIndex={0}
      onClick={onClick}
      onKeyDown={(e) => {
        if (e.key === 'Enter' || e.key === ' ') {
          e.preventDefault()
          onClick()
        }
      }}
    >
      <p
        style={{
          fontWeight: 600,
          fontSize: '1rem',
          color: 'var(--color-primary)',
          margin: 0,
          marginBottom: 4,
        }}
      >
        {institution.name}
      </p>
      <p
        style={{
          fontSize: '0.875rem',
          color: 'var(--mantine-color-gray-6)',
          margin: 0,
        }}
      >
        {institution.city}, {institution.state}
      </p>
      {(hasLocation || hasState) && (
        <div
          style={{
            display: 'flex',
            gap: 16,
            marginTop: 8,
            fontSize: '0.875rem',
            color: 'var(--mantine-color-gray-6)',
          }}
        >
          {hasLocation && institution.distance != null && (
            <span
              data-testid="distance"
              style={{ display: 'inline-flex', alignItems: 'center', gap: 4 }}
