import { describe, it, expect, vi, beforeEach } from 'vitest'
import { useSavedSearchStore } from './savedSearchStore'

const mockQuery = vi.fn()
const mockMutation = vi.fn()

vi.mock('@/lib/urqlClient', () => ({
  urqlClient: {
    query: (...args: unknown[]) => ({ toPromise: () => mockQuery(...args) }),
    mutation: (...args: unknown[]) => ({ toPromise: () => mockMutation(...args) }),
  },
}))

vi.mock('@/lib/supabase', () => ({
  supabase: {
    auth: {
      getSession: vi.fn().mockResolvedValue({ data: { session: null } }),
      onAuthStateChange: vi
        .fn()
        .mockReturnValue({ data: { subscription: { unsubscribe: vi.fn() } } }),
    },
  },
}))

beforeEach(() => {
  useSavedSearchStore.setState({ searches: [], loaded: false, loading: false })
  mockQuery.mockReset()
  mockMutation.mockReset()
})

describe('savedSearchStore', () => {
  it('starts with empty state', () => {
    const state = useSavedSearchStore.getState()
    expect(state.searches).toEqual([])
    expect(state.loaded).toBe(false)
    expect(state.loading).toBe(false)
  })

  it('load fetches saved searches', async () => {
    const items = [
      {
        id: '1',
        name: 'Test Search',
        searchState: 'name=MIT',
        createdAt: '2026-01-01T00:00:00Z',
        updatedAt: '2026-01-01T00:00:00Z',
      },
    ]
    mockQuery.mockResolvedValue({ data: { savedSearches: items } })

    await useSavedSearchStore.getState().load()

    expect(useSavedSearchStore.getState().searches).toEqual(items)
    expect(useSavedSearchStore.getState().loaded).toBe(true)
  })

  it('load skips if already loaded', async () => {
    useSavedSearchStore.setState({ loaded: true })
    await useSavedSearchStore.getState().load()
    expect(mockQuery).not.toHaveBeenCalled()
  })

  it('save adds to searches', async () => {
    const saved = {
      id: '2',
      name: 'New Search',
      searchState: 'name=Harvard',
      createdAt: '2026-01-02T00:00:00Z',
      updatedAt: '2026-01-02T00:00:00Z',
    }
    mockMutation.mockResolvedValue({ data: { saveSearch: saved } })

    const result = await useSavedSearchStore.getState().save('New Search', 'name=Harvard')

    expect(result).toEqual(saved)
    expect(useSavedSearchStore.getState().searches).toHaveLength(1)
    expect(useSavedSearchStore.getState().searches[0].name).toBe('New Search')
  })

  it('remove deletes from searches', async () => {
    useSavedSearchStore.setState({
      searches: [
        {
          id: '1',
          name: 'Test',
          searchState: 'a=b',
          createdAt: '',
          updatedAt: '',
        },
      ],
    })
    mockMutation.mockResolvedValue({ data: { deleteSavedSearch: true } })

    const result = await useSavedSearchStore.getState().remove('1')

    expect(result).toBe(true)
    expect(useSavedSearchStore.getState().searches).toHaveLength(0)
  })

  it('remove returns false on failure', async () => {
    mockMutation.mockResolvedValue({ data: { deleteSavedSearch: false } })

    const result = await useSavedSearchStore.getState().remove('999')
    expect(result).toBe(false)
  })

  it('clear resets state', () => {
    useSavedSearchStore.setState({
      searches: [{ id: '1', name: 'X', searchState: '', createdAt: '', updatedAt: '' }],
      loaded: true,
    })
    useSavedSearchStore.getState().clear()

    expect(useSavedSearchStore.getState().searches).toEqual([])
    expect(useSavedSearchStore.getState().loaded).toBe(false)
  })
})

