import { describe, it, expect, vi, beforeEach } from 'vitest'
import { useBookmarkStore } from './bookmarkStore'

const mockQuery = vi.fn()
const mockMutation = vi.fn()

vi.mock('@/lib/urqlClient', () => ({
  urqlClient: {
    query: (...args: unknown[]) => ({ toPromise: () => mockQuery(...args) }),
    mutation: (...args: unknown[]) => ({ toPromise: () => mockMutation(...args) }),
  },
}))

vi.mock('@/lib/supabase', () => ({
  supabase: {
    auth: {
      getSession: vi.fn().mockResolvedValue({ data: { session: null } }),
      onAuthStateChange: vi
        .fn()
        .mockReturnValue({ data: { subscription: { unsubscribe: vi.fn() } } }),
    },
  },
}))

beforeEach(() => {
  useBookmarkStore.setState({
    bookmarkedIDs: new Set(),
    institutions: [],
    loaded: false,
    loading: false,
  })
  mockQuery.mockReset()
  mockMutation.mockReset()
})

describe('bookmarkStore', () => {
  it('starts with empty state', () => {
    const state = useBookmarkStore.getState()
    expect(state.bookmarkedIDs.size).toBe(0)
    expect(state.institutions).toEqual([])
    expect(state.loaded).toBe(false)
    expect(state.loading).toBe(false)
  })

  it('loadAll fetches bookmarked institutions', async () => {
    const items = [
      {
        id: '1',
        unitID: '100724',
        name: 'Alabama State University',
        city: 'Montgomery',
        state: 'AL',
        createdAt: '2026-01-01T00:00:00Z',
      },
    ]
    mockQuery.mockResolvedValue({ data: { bookmarkedInstitutions: items } })

    await useBookmarkStore.getState().loadAll()

    expect(useBookmarkStore.getState().institutions).toEqual(items)
    expect(useBookmarkStore.getState().bookmarkedIDs.has('100724')).toBe(true)
    expect(useBookmarkStore.getState().loaded).toBe(true)
  })

  it('checkBatch adds IDs to the set', async () => {
    mockQuery.mockResolvedValue({ data: { bookmarkedUnitIDs: ['100724'] } })

    await useBookmarkStore.getState().checkBatch(['100724', '101240'])

    expect(useBookmarkStore.getState().bookmarkedIDs.has('100724')).toBe(true)
    expect(useBookmarkStore.getState().bookmarkedIDs.has('101240')).toBe(false)
  })

  it('add bookmarks optimistically and updates on success', async () => {
    const item = {
      id: '2',
      unitID: '101240',
      name: 'Gadsden State Community College',
      city: 'Gadsden',
      state: 'AL',
      createdAt: '2026-01-02T00:00:00Z',
    }
    mockMutation.mockResolvedValue({ data: { addBookmark: item } })

    const result = await useBookmarkStore.getState().add('101240')

    expect(result).toBe(true)
    expect(useBookmarkStore.getState().bookmarkedIDs.has('101240')).toBe(true)
    expect(useBookmarkStore.getState().institutions).toHaveLength(1)
    expect(useBookmarkStore.getState().institutions[0].unitID).toBe('101240')
  })

  it('add rolls back on failure', async () => {
    mockMutation.mockResolvedValue({ data: null })

    const result = await useBookmarkStore.getState().add('101240')

    expect(result).toBe(false)
    expect(useBookmarkStore.getState().bookmarkedIDs.has('101240')).toBe(false)
  })

  it('remove unbookmarks optimistically and updates on success', async () => {
    useBookmarkStore.setState({
      bookmarkedIDs: new Set(['100724']),
      institutions: [
        {
          id: '1',
          unitID: '100724',
          name: 'Alabama State University',
          city: 'Montgomery',
          state: 'AL',
          createdAt: '2026-01-01T00:00:00Z',
        },
      ],
    })
    mockMutation.mockResolvedValue({ data: { removeBookmark: true } })

    const result = await useBookmarkStore.getState().remove('100724')

    expect(result).toBe(true)
    expect(useBookmarkStore.getState().bookmarkedIDs.has('100724')).toBe(false)
    expect(useBookmarkStore.getState().institutions).toHaveLength(0)
  })

  it('remove rolls back on failure', async () => {
    useBookmarkStore.setState({ bookmarkedIDs: new Set(['100724']) })
    mockMutation.mockResolvedValue({ data: null })

    const result = await useBookmarkStore.getState().remove('100724')

    expect(result).toBe(false)
    expect(useBookmarkStore.getState().bookmarkedIDs.has('100724')).toBe(true)
  })

  it('isBookmarked returns correct state', () => {
    useBookmarkStore.setState({ bookmarkedIDs: new Set(['100724']) })

    expect(useBookmarkStore.getState().isBookmarked('100724')).toBe(true)
    expect(useBookmarkStore.getState().isBookmarked('101240')).toBe(false)
  })

  it('clear resets state', () => {
    useBookmarkStore.setState({
      bookmarkedIDs: new Set(['100724']),
      institutions: [
        {
          id: '1',
          unitID: '100724',
          name: 'Test',
          city: 'City',
          state: 'ST',
          createdAt: '',
        },
      ],
      loaded: true,
    })
    useBookmarkStore.getState().clear()

    expect(useBookmarkStore.getState().bookmarkedIDs.size).toBe(0)
    expect(useBookmarkStore.getState().institutions).toEqual([])
    expect(useBookmarkStore.getState().loaded).toBe(false)
  })
})

