import { describe, it, expect, vi, beforeEach } from 'vitest'
import { screen } from '@testing-library/react'
import userEvent from '@testing-library/user-event'
import { renderWithMantine } from '@/test/render'
import { BookmarkButton } from './BookmarkButton'
import { useAuthStore } from '@/stores/authStore'
import { useBookmarkStore } from '@/stores/bookmarkStore'

vi.mock('@/lib/urqlClient', () => ({
  urqlClient: {
    query: () => ({ toPromise: vi.fn().mockResolvedValue({ data: null }) }),
    mutation: () => ({ toPromise: vi.fn().mockResolvedValue({ data: null }) }),
  },
}))

vi.mock('@/lib/supabase', () => ({
  supabase: {
    auth: {
      getSession: vi.fn().mockResolvedValue({ data: { session: null } }),
      onAuthStateChange: vi
        .fn()
        .mockReturnValue({ data: { subscription: { unsubscribe: vi.fn() } } }),
    },
  },
}))

beforeEach(() => {
  useAuthStore.setState({ user: null, session: null, loading: false })
  useBookmarkStore.setState({
    bookmarkedIDs: new Set(),
    institutions: [],
    loaded: false,
    loading: false,
  })
})

describe('BookmarkButton', () => {
  it('renders disabled for anonymous users', () => {
    renderWithMantine(<BookmarkButton unitID="100724" />)

    const button = screen.getByTestId('bookmark-button')
    expect(button).toBeDisabled()
  })

  it('renders enabled for authenticated users', () => {
    useAuthStore.setState({ user: { id: 'user-1' } as never })
    renderWithMantine(<BookmarkButton unitID="100724" />)

    const button = screen.getByTestId('bookmark-button')
    expect(button).not.toBeDisabled()
    expect(button).toHaveAttribute('aria-label', 'Bookmark')
  })

  it('shows filled heart when bookmarked', () => {
    useAuthStore.setState({ user: { id: 'user-1' } as never })
    useBookmarkStore.setState({ bookmarkedIDs: new Set(['100724']) })
    renderWithMantine(<BookmarkButton unitID="100724" />)

    const button = screen.getByTestId('bookmark-button')
    expect(button).toHaveAttribute('aria-label', 'Remove bookmark')
  })

  it('calls add when clicking unbookmarked', async () => {
    const addMock = vi.fn().mockResolvedValue(true)
    useAuthStore.setState({ user: { id: 'user-1' } as never })
    useBookmarkStore.setState({ bookmarkedIDs: new Set(), add: addMock })

    renderWithMantine(<BookmarkButton unitID="100724" />)
    await userEvent.click(screen.getByTestId('bookmark-button'))

    expect(addMock).toHaveBeenCalledWith('100724')
  })

  it('calls remove when clicking bookmarked', async () => {
    const removeMock = vi.fn().mockResolvedValue(true)
    useAuthStore.setState({ user: { id: 'user-1' } as never })
    useBookmarkStore.setState({ bookmarkedIDs: new Set(['100724']), remove: removeMock })

    renderWithMantine(<BookmarkButton unitID="100724" />)
    await userEvent.click(screen.getByTestId('bookmark-button'))

    expect(removeMock).toHaveBeenCalledWith('100724')
  })
})

