import { describe, it, expect, vi } from 'vitest'
import { screen } from '@testing-library/react'
import userEvent from '@testing-library/user-event'
import { renderWithMantine } from '@/test/render'
import { InstitutionCard, InstitutionCardSkeleton } from './InstitutionCard'
import type { SearchInstitution } from './types'

const BASE_INSTITUTION: SearchInstitution = {
  unitID: '166683',
  name: 'Massachusetts Institute of Technology',
  city: 'Cambridge',
  state: 'MA',
}

describe('InstitutionCard', () => {
  it('renders institution name, city, and state', () => {
    renderWithMantine(
      <InstitutionCard
        institution={BASE_INSTITUTION}
        hasLocation={false}
        hasState={false}
        onClick={() => {}}
      />,
    )
    expect(screen.getByText('Massachusetts Institute of Technology')).toBeInTheDocument()
    expect(screen.getByText('Cambridge, MA')).toBeInTheDocument()
  })

  it('calls onClick when clicked', async () => {
    const user = userEvent.setup()
    const onClick = vi.fn()
    renderWithMantine(
      <InstitutionCard
        institution={BASE_INSTITUTION}
        hasLocation={false}
        hasState={false}
        onClick={onClick}
      />,
    )
    await user.click(screen.getByRole('button'))
    expect(onClick).toHaveBeenCalledOnce()
  })

  it('calls onClick on Enter key', async () => {
    const user = userEvent.setup()
    const onClick = vi.fn()
    renderWithMantine(
      <InstitutionCard
        institution={BASE_INSTITUTION}
        hasLocation={false}
        hasState={false}
        onClick={onClick}
      />,
    )
    screen.getByRole('button').focus()
    await user.keyboard('{Enter}')
    expect(onClick).toHaveBeenCalledOnce()
  })

  it('calls onClick on Space key', async () => {
    const user = userEvent.setup()
    const onClick = vi.fn()
    renderWithMantine(
      <InstitutionCard
        institution={BASE_INSTITUTION}
        hasLocation={false}
        hasState={false}
        onClick={onClick}
      />,
    )
    screen.getByRole('button').focus()
    await user.keyboard(' ')
    expect(onClick).toHaveBeenCalledOnce()
  })

  it('shows distance when hasLocation is true and distance is present', () => {
    const inst = { ...BASE_INSTITUTION, distance: 42.3 }
    renderWithMantine(
      <InstitutionCard institution={inst} hasLocation={true} hasState={false} onClick={() => {}} />,
    )
    expect(screen.getByTestId('distance')).toHaveTextContent('42 mi')
  })

  it('shows "< 1 mi" for distances under 1', () => {
    const inst = { ...BASE_INSTITUTION, distance: 0.3 }
    renderWithMantine(
      <InstitutionCard institution={inst} hasLocation={true} hasState={false} onClick={() => {}} />,
    )
    expect(screen.getByTestId('distance')).toHaveTextContent('< 1 mi')
